INSERT OR IGNORE INTO projects (slug,number,title_tr,title_en,subtitle_tr,subtitle_en,year,location_tr,location_en,tag,area_m2,status,description_tr,description_en,sort_order,published) VALUES ('karakoy-014','014','Karaköy Apartmanı','Karaköy Apartment','Levanten bir yapının yeniden yorumu','Reinterpretation of a Levantine building',2026,'İstanbul','Istanbul','Residential',240,'In Progress','On dokuzuncu yüzyıl bir Levanten apartmanının ikinci katı, üç odalı bir eşik dizisine dönüşüyor.','The second floor of a 19th-century Levantine apartment transforms into a three-room sequence of thresholds.',140,1);
INSERT OR IGNORE INTO projects (slug,number,title_tr,title_en,subtitle_tr,subtitle_en,year,location_tr,location_en,tag,area_m2,status,description_tr,description_en,sort_order,published) VALUES ('olive-house-013','013','Olive House','Olive House','Zeytinliğin içinde bir ev','A house within the olive grove',2025,'Bodrum','Bodrum','Residential',320,'Completed','Bir zeytinliğin içine yerleştirilen bu konut, ağaçların ritmiyle bütünleşen uzun, yatay bir plana sahiptir.','Set within an olive grove, this house has a long horizontal plan that integrates with the rhythm of the trees.',130,1);
INSERT OR IGNORE INTO projects (slug,number,title_tr,title_en,subtitle_tr,subtitle_en,year,location_tr,location_en,tag,area_m2,status,description_tr,description_en,sort_order,published) VALUES ('atelier-b-012','012','Atelier B','Atelier B','Sade bir çalışma mekânı','A quiet workspace',2025,'Antalya','Antalya','Workspace',180,'Completed','Tek bir hacimden oluşan bu atölye, doğal ışığı çalışmanın merkezine koyar.','This single-volume atelier places natural light at the centre of work.',120,1);
INSERT OR IGNORE INTO projects (slug,number,title_tr,title_en,subtitle_tr,subtitle_en,year,location_tr,location_en,tag,area_m2,status,description_tr,description_en,sort_order,published) VALUES ('antalya-pavilion-011','011','Antalya Pavilion','Antalya Pavilion','Küçük ölçekli kamusal bir yapı','A small-scale public building',2024,'Antalya','Antalya','Cultural',90,'Completed','Kent parkının kenarında, ince bir çatıyla örtülü bu köşk; gölge, oturma ve geçiş için tasarlanmıştır.','At the edge of a city park, this pavilion covered by a thin roof is designed for shade, seating, and passage.',110,1);
INSERT OR IGNORE INTO projects (slug,number,title_tr,title_en,subtitle_tr,subtitle_en,year,location_tr,location_en,tag,area_m2,status,description_tr,description_en,sort_order,published) VALUES ('cihangir-loft-010','010','Cihangir Loft','Cihangir Loft','Tarihi bir yapının çağdaş yorumu','Contemporary interpretation of a historic building',2024,'İstanbul','Istanbul','Residential',110,'Completed','Cihangir''in dar sokaklarından birinde, eski bir binanın çatı katı; açık plan ve yüksek tavan ile yeniden tanımlanıyor.','On one of Cihangir''s narrow streets, the top floor of an old building is redefined with an open plan and high ceiling.',100,1);
INSERT OR IGNORE INTO projects (slug,number,title_tr,title_en,subtitle_tr,subtitle_en,year,location_tr,location_en,tag,area_m2,status,description_tr,description_en,sort_order,published) VALUES ('house-astra-009','009','House Astra','House Astra','Çeşme''nin sert ışığında bir konut','A residence in the harsh light of Çeşme',2023,'Çeşme','Çeşme','Residential',380,'Completed','Ege ikliminin sert ışığına karşı tasarlanan bu konut, derin gölgeler ve dar açıklıklarla kendine özgü bir iç atmosfer yaratır.','Designed against the harsh light of the Aegean climate, this residence creates its own interior atmosphere.',90,1);
INSERT OR IGNORE INTO projects (slug,number,title_tr,title_en,subtitle_tr,subtitle_en,year,location_tr,location_en,tag,area_m2,status,description_tr,description_en,sort_order,published) VALUES ('quiet-atelier-008','008','Quiet Atelier','Quiet Atelier','Sessizliğin bir çalışma mekânına dönüşümü','Silence transformed into a workspace',2023,'İstanbul','Istanbul','Workspace',220,'Completed','İstanbul''un gürültüsünün ortasında, bir avlunun derinliğinde kurulan bu atölye; akustik yalıtım ve doğal malzeme seçimiyle sessizliği inşa eder.','Established in the depths of a courtyard in the midst of Istanbul''s noise, this atelier constructs silence.',80,1);
