INSERT OR IGNORE INTO journal_posts (slug,kind,title_tr,title_en,excerpt_tr,excerpt_en,body_tr,body_en,author,read_time,published_at,published) VALUES ('bir-esigin-kisa-tarihi','Essay','Bir eşiğin kısa tarihi','A brief history of a threshold','Likya kayalarından modern apartmanlara: bir mekânı diğerinden ayıran o ince dilim üzerine on iki not.','From Lycian rocks to modern apartments: twelve notes on that thin slice that separates one space from another.','Likya kayalarından modern apartmanlara: bir mekânı diğerinden ayıran o ince dilim üzerine on iki not.','From Lycian rocks to modern apartments: twelve notes on that thin slice that separates one space from another.','Eda Aksel',6,'2026-05-12 09:00:00',1);
INSERT OR IGNORE INTO journal_posts (slug,kind,title_tr,title_en,excerpt_tr,excerpt_en,body_tr,body_en,author,read_time,published_at,published) VALUES ('travertinin-ikinci-hayati','Field Note','Travertinin ikinci hayatı','The second life of travertine','Antalya''nın eski bir ocağında geçirdiğimiz bir hafta. Kaynaktan iki yıl sonra, malzemenin neresi sahiden iyi yaşlanmış?','A week spent in an old quarry in Antalya. Two years from the source, where has the material aged well?','Antalya''nın eski bir ocağında geçirdiğimiz bir hafta.','A week spent in an old quarry in Antalya.','Mert Yıldız',4,'2026-05-03 09:00:00',1);
INSERT OR IGNORE INTO journal_posts (slug,kind,title_tr,title_en,excerpt_tr,excerpt_en,body_tr,body_en,author,read_time,published_at,published) VALUES ('bir-muvekille-uc-oturum','Konuşma','Bir müvekkille üç oturum','Three sessions with a client','Karaköy 014''ün başlangıcı: tek bir A4 üzerine yazılmış bir sayfa, sonra bir hafta süren bir sessizlik.','The beginning of Karaköy 014: a single page written on an A4, then a week of silence.','Karaköy 014''ün başlangıcı: tek bir A4 üzerine yazılmış bir sayfa.','The beginning of Karaköy 014: a single page written on an A4.','Eda Aksel',8,'2026-04-22 09:00:00',1);
INSERT OR IGNORE INTO journal_posts (slug,kind,title_tr,title_en,excerpt_tr,excerpt_en,body_tr,body_en,author,read_time,published_at,published) VALUES ('sessizligin-akustigi','Field Note','Sessizliğin akustiği','The acoustics of silence','Mekânda boşluk değil, sesin nasıl davrandığı önemlidir. Üç oda, üç farklı ses karakteri.','In space it is not the void but how sound behaves that matters. Three rooms, three different acoustic characters.','Mekânda boşluk değil, sesin nasıl davrandığı önemlidir.','In space it is not the void but how sound behaves that matters.','Nehir Dağ',3,'2026-04-18 09:00:00',1);
INSERT OR IGNORE INTO journal_posts (slug,kind,title_tr,title_en,excerpt_tr,excerpt_en,body_tr,body_en,author,read_time,published_at,published) VALUES ('tavan-yuksekligi-ustune','Essay','Tavan yüksekliği üstüne','On ceiling height','Bir oda neden 2.70 değil de 3.20 olmalı? Türkiye''deki konut yönetmeliğinin sessiz açıkları üzerine.','Why should a room be 3.20 rather than 2.70? On the silent gaps in Turkey''s housing regulations.','Bir oda neden 2.70 değil de 3.20 olmalı?','Why should a room be 3.20 rather than 2.70?','Eda Aksel',7,'2026-04-01 09:00:00',1);
INSERT OR IGNORE INTO journal_posts (slug,kind,title_tr,title_en,excerpt_tr,excerpt_en,body_tr,body_en,author,read_time,published_at,published) VALUES ('kitap-pallasmaa','Book','Kitap · Pallasmaa','Book · Pallasmaa','Juhani Pallasmaa''nın Tenin Gözleri''ni yeniden okuduk. Üç paragraf, üç düşünce.','We reread Juhani Pallasmaa''s The Eyes of the Skin. Three paragraphs, three thoughts.','Juhani Pallasmaa''nın Tenin Gözleri''ni yeniden okuduk.','We reread Juhani Pallasmaa''s The Eyes of the Skin.','Selim Koç',3,'2026-03-18 09:00:00',1);
INSERT OR IGNORE INTO journal_posts (slug,kind,title_tr,title_en,excerpt_tr,excerpt_en,body_tr,body_en,author,read_time,published_at,published) VALUES ('karakoy-doksan-gun','Field Note','Karaköy · Doksan gün','Karaköy · Ninety days','Karaköy 014 şantiyesinden günlük notlar. Üç aylık inşaat sürecinin seçilmiş anları.','Daily notes from the Karaköy 014 construction site. Selected moments from three months of construction.','Karaköy 014 şantiyesinden günlük notlar.','Daily notes from the Karaköy 014 construction site.','Mert Yıldız',5,'2026-03-05 09:00:00',1);
INSERT OR IGNORE INTO journal_posts (slug,kind,title_tr,title_en,excerpt_tr,excerpt_en,body_tr,body_en,author,read_time,published_at,published) VALUES ('isik-haritalamak','Essay','Işık haritalamak','Mapping light','Her projede ilk üç hafta: güneş açısını, yönü ve mevsimi çalışmak. Bir ışık haritası nasıl okunur?','The first three weeks of every project: studying solar angle, orientation and season. How do you read a light map?','Her projede ilk üç hafta: güneş açısını, yönü ve mevsimi çalışmak.','The first three weeks of every project: studying solar angle, orientation and season.','Eda Aksel',5,'2026-02-19 09:00:00',1);
INSERT OR IGNORE INTO journal_posts (slug,kind,title_tr,title_en,excerpt_tr,excerpt_en,body_tr,body_en,author,read_time,published_at,published) VALUES ('antalya-aralik-isigi','Field Note','Antalya · Aralık ışığı','Antalya · December light','Aralık''ta Antalya''da ışık farklı düşer. Bir hafta boyunca notlar.','In December, light falls differently in Antalya. Notes from a week.','Aralık''ta Antalya''da ışık farklı düşer.','In December, light falls differently in Antalya.','Mert Yıldız',3,'2026-02-02 09:00:00',1);
INSERT OR IGNORE INTO journal_posts (slug,kind,title_tr,title_en,excerpt_tr,excerpt_en,body_tr,body_en,author,read_time,published_at,published) VALUES ('bir-kapinin-dogru-agirligi','Essay','Bir kapının doğru ağırlığı','The right weight of a door','Bir kapı ne kadar ağır olmalı? Malzeme, menteşe ve beklenti üzerine.','How heavy should a door be? On material, hinge, and expectation.','Bir kapı ne kadar ağır olmalı?','How heavy should a door be?','Eda Aksel',4,'2026-01-15 09:00:00',1);
INSERT OR IGNORE INTO journal_posts (slug,kind,title_tr,title_en,excerpt_tr,excerpt_en,body_tr,body_en,author,read_time,published_at,published) VALUES ('olive-house-sonrasi','Konuşma','Olive House sonrası','After Olive House','Proje tamamlandıktan sonra müvekkille bir söyleşi. Beklentiler ve gerçek.','A conversation with the client after the project was completed. Expectations and reality.','Proje tamamlandıktan sonra müvekkille bir söyleşi.','A conversation with the client after the project was completed.','Nehir Dağ',6,'2025-12-21 09:00:00',1);
INSERT OR IGNORE INTO journal_posts (slug,kind,title_tr,title_en,excerpt_tr,excerpt_en,body_tr,body_en,author,read_time,published_at,published) VALUES ('zumthor-uzerine-uc-paragraf','Book','Zumthor üzerine üç paragraf','Three paragraphs on Zumthor','Peter Zumthor''u yeniden okuduk. Atmosferler kitabından seçilmiş üç alıntı.','We reread Peter Zumthor. Three selected quotes from the book Atmospheres.','Peter Zumthor''u yeniden okuduk.','We reread Peter Zumthor.','Selim Koç',2,'2025-11-04 09:00:00',1);
INSERT OR IGNORE INTO journal_posts (slug,kind,title_tr,title_en,excerpt_tr,excerpt_en,body_tr,body_en,author,read_time,published_at,published) VALUES ('beton-tas-ve-sabir','Essay','Beton, taş, ve sabır','Concrete, stone, and patience','Malzemenin zamanla nasıl değiştiğini izlemek, bir mimarlık pratiğinin en önemli parçasıdır.','Watching how materials change over time is the most important part of an architectural practice.','Malzemenin zamanla nasıl değiştiğini izlemek.','Watching how materials change over time.','Nehir Dağ',5,'2025-10-08 09:00:00',1);
INSERT OR IGNORE INTO journal_posts (slug,kind,title_tr,title_en,excerpt_tr,excerpt_en,body_tr,body_en,author,read_time,published_at,published) VALUES ('bir-koridor-ustune','Field Note','Bir koridor üstüne','On a corridor','Bir koridorun uzunluğu, genişliği ve ışığı nasıl bir duygu yaratır? Olive House''dan notlar.','How does the length, width and light of a corridor create a feeling? Notes from Olive House.','Bir koridorun uzunluğu, genişliği ve ışığı nasıl bir duygu yaratır?','How does the length, width and light of a corridor create a feeling?','Mert Yıldız',3,'2025-09-02 09:00:00',1);
INSERT OR IGNORE INTO journal_posts (slug,kind,title_tr,title_en,excerpt_tr,excerpt_en,body_tr,body_en,author,read_time,published_at,published) VALUES ('bosluk-doluluktan-once','Essay','Boşluk doluluktan önce','Emptiness before fullness','Bir mekânı tasarlamadan önce, orada ne olmayacağını düşünmek gerekir.','Before designing a space, one must think about what will not be in it.','Bir mekânı tasarlamadan önce, orada ne olmayacağını düşünmek gerekir.','Before designing a space, one must think about what will not be in it.','Eda Aksel',4,'2025-07-30 09:00:00',1);
INSERT OR IGNORE INTO journal_posts (slug,kind,title_tr,title_en,excerpt_tr,excerpt_en,body_tr,body_en,author,read_time,published_at,published) VALUES ('yapay-isik-ustune','Konuşma','Yapay ışık üstüne','On artificial light','Doğal ışığı seven bir mimarlık bürosu olarak yapay ışıkla nasıl barışıyoruz?','As an architecture studio that loves natural light, how do we make peace with artificial light?','Doğal ışığı seven bir mimarlık bürosu olarak yapay ışıkla nasıl barışıyoruz?','As an architecture studio that loves natural light, how do we make peace with artificial light?','Nehir Dağ',5,'2025-06-11 09:00:00',1);

