-- APPROACH: PILLARS
-- -----------------------------------------------
INSERT OR IGNORE INTO approach_pillars (num,label_tr,label_en,title_tr,title_en,lede_tr,lede_en,body_tr,body_en,rules_tr,rules_en,sort_order) VALUES ('i','Sabit · 01','Constant · 01','Oran','Proportion','Her mekân önce bir sayı dizisidir. Tavan, kapı, ışığın açısı — birbiriyle konuşur.','Every space is first a sequence of numbers. Ceiling, door, the angle of light — they speak to each other.','Her projede üç temel oran kararı alırız: tavan yüksekliğinin tabana, açıklığın duvara, doğal ışığın yapaya.','In every project we make three fundamental proportional decisions: ceiling height to floor, opening to wall, natural light to built surface.','[{"key":"§01","value":"Tavan yüksekliği her zaman ölçülür, hesaplanır, korunur."},{"key":"§02","value":"Açıklıkların oranı 1:1.5 ile 1:1.8 arasında tutulur."},{"key":"§03","value":"Her mekânın bir hâkim eksenli ölçüsü vardır."}]','[{"key":"§01","value":"Ceiling height is always measured, calculated, preserved."},{"key":"§02","value":"Opening ratios are kept between 1:1.5 and 1:1.8."},{"key":"§03","value":"Every space has one dominant axial dimension."}]',10);
INSERT OR IGNORE INTO approach_pillars (num,label_tr,label_en,title_tr,title_en,lede_tr,lede_en,body_tr,body_en,rules_tr,rules_en,sort_order) VALUES ('ii','Sabit · 02','Constant · 02','Işık','Light','Bir odayı önce ışık tasarlar. Yapay ışığı doğal olanın ardından, sessizce çağırırız.','Light designs a room first. We invite artificial light quietly, following the natural.','Güneş açısı, yön ve mevsim her projede ilk üç haftanın çalışmasıdır.','Solar angle, orientation and season are the work of the first three weeks on every project.','[{"key":"§04","value":"Pencere oranları yön ve mevsime göre belirlenir."},{"key":"§05","value":"Yapay ışık 2700K–3000K aralığında tutulur."},{"key":"§06","value":"Hiçbir lamba doğrudan görünür konumda durmaz."}]','[{"key":"§04","value":"Window proportions are determined by orientation and season."},{"key":"§05","value":"Artificial light is kept in the 2700K–3000K range."},{"key":"§06","value":"No lamp stands in a directly visible position."}]',20);
INSERT OR IGNORE INTO approach_pillars (num,label_tr,label_en,title_tr,title_en,lede_tr,lede_en,body_tr,body_en,rules_tr,rules_en,sort_order) VALUES ('iii','Sabit · 03','Constant · 03','Malzeme','Matter','Zamanla daha güzel olan her şey kabuldür. Yenilik değil, yaşlanma kalitesini ararız.','Anything that becomes more beautiful with time is acceptable. We look for ageing quality, not novelty.','Travertin, ham keten, ağartılmamış meşe, mat pirinç, doğal kireç boya.','Travertine, raw linen, unbleached oak, matt brass, natural lime paint.','[{"key":"§07","value":"Bir mekânda en fazla beş ana malzeme."},{"key":"§08","value":"Hiçbir yüzey parlak değildir; yalnızca açık, doğal, mat."},{"key":"§09","value":"Her malzeme kaynakta görülerek seçilir, fotoğraftan değil."}]','[{"key":"§07","value":"No more than five primary materials in a space."},{"key":"§08","value":"No surface is shiny; only light, natural, matt."},{"key":"§09","value":"Every material is selected by seeing it at source, not from photographs."}]',30);

-- -----------------------------------------------
-- APPROACH: PROCESS STAGES
-- -----------------------------------------------
INSERT OR IGNORE INTO approach_stages (num,title_tr,title_en,duration,description_tr,description_en,sort_order) VALUES ('01','Söyleşi','Conversation','2–3 hafta','2–3 hafta süren, tek bir sayfaya sığabilecek kadar netleşen ilk diyalog. Brief değil, anlamak.','An initial dialogue lasting 2–3 weeks, clarified enough to fit on a single page. Not a brief — understanding.',10);
INSERT OR IGNORE INTO approach_stages (num,title_tr,title_en,duration,description_tr,description_en,sort_order) VALUES ('02','Kavram','Concept','4–6 hafta','Üç sabit (oran, ışık, malzeme) etrafında üç farklı kavram önerisi. Yalnızca birine devam edilir.','Three different concept proposals around the three constants. Only one is continued.',20);
INSERT OR IGNORE INTO approach_stages (num,title_tr,title_en,duration,description_tr,description_en,sort_order) VALUES ('03','Tasarım','Design','10–14 hafta','Plan, kesit, görünüş, detay. Her hafta tek bir uzun toplantıyla ilerleriz; arada sessizlik kalır.','Plan, section, elevation, detail. We proceed with one long meeting per week; silence remains in between.',30);
INSERT OR IGNORE INTO approach_stages (num,title_tr,title_en,duration,description_tr,description_en,sort_order) VALUES ('04','İnşaat','Build','8–14 ay','Uygulayıcı seçimi, ihale, şantiye denetimi. Haftada en az bir saha ziyareti, her detay için bir mock-up.','Contractor selection, tender, site supervision. At least one site visit per week, one mock-up per detail.',40);
INSERT OR IGNORE INTO approach_stages (num,title_tr,title_en,duration,description_tr,description_en,sort_order) VALUES ('05','Teslim','Handover','1 hafta','Anahtar değil, bir kullanım kitapçığı teslim ederiz: malzeme bakımı, ışık senaryoları, ileri öneriler.','We deliver not a key but a user manual: material care, lighting scenarios, further recommendations.',50);

-- -----------------------------------------------
-- APPROACH: PRINCIPLES
-- -----------------------------------------------
INSERT OR IGNORE INTO approach_principles (yes_tr,yes_en,no_tr,no_en,sort_order) VALUES ('Az kelime.','Few words.','Süperlatif başlık.','Superlative headline.',10);
INSERT OR IGNORE INTO approach_principles (yes_tr,yes_en,no_tr,no_en,sort_order) VALUES ('Tek bir hâkim oran.','One dominant proportion.','Birden çok hâkim eksen.','More than one dominant axis.',20);
INSERT OR IGNORE INTO approach_principles (yes_tr,yes_en,no_tr,no_en,sort_order) VALUES ('Doğal ışığa öncelik.','Priority to natural light.','Parlak yüzeyler.','Shiny surfaces.',30);
INSERT OR IGNORE INTO approach_principles (yes_tr,yes_en,no_tr,no_en,sort_order) VALUES ('Beş malzeme, en fazla.','Five materials, at most.','Trend renk panosu.','Trend colour board.',40);
INSERT OR IGNORE INTO approach_principles (yes_tr,yes_en,no_tr,no_en,sort_order) VALUES ('Yaşlanma kalitesi.','Ageing quality.','Fotoğraf-gerçekçi render.','Photo-realistic render.',50);
INSERT OR IGNORE INTO approach_principles (yes_tr,yes_en,no_tr,no_en,sort_order) VALUES ('Sahaya haftada bir ziyaret.','One site visit per week.','Aşırı dekorasyon.','Over-decoration.',60);
INSERT OR IGNORE INTO approach_principles (yes_tr,yes_en,no_tr,no_en,sort_order) VALUES ('Her detay için bir mock-up.','One mock-up per detail.','Hızlı karar, geniş malzeme paleti.','Quick decision, wide material palette.',70);
INSERT OR IGNORE INTO approach_principles (yes_tr,yes_en,no_tr,no_en,sort_order) VALUES ('Müvekkille uzun, sade söyleşi.','Long, plain conversation with the client.','"Lüks", "ultra", "premium".','"Luxury", "ultra", "premium".',80);

